solutions.javascript:
// Function to validate a Git tag name
function validateTagName(tagName) {
  if (tagName.startsWith("v")) {
    return /^[v\d\.]+$/.test(tagName);
  }
  return false;
}

solutions.python:
class Solution:
  def validateTagName(self, tag_name: str) -> bool:
    if tag_name.startswith("v"):
      return bool(re.match("^[v\\d\\.]+$", tag_name))
    return False
